create table dirkspzm32.lvs_inventur_job_kopf (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(6, 0) not null enable,
    inventur_id          number(*, 0) not null enable,
    inv_type             varchar2(50 char) not null enable,
    info                 varchar2(255 char),
    lgr_ort              number(*, 5),
    lgr_dim_g_von        number(*, 5),
    lgr_dim_g_bis        number(*, 5),
    lgr_dim_r_von        number(*, 5),
    lgr_dim_r_bis        number(*, 5),
    lgr_dim_p_von        number(*, 5),
    lgr_dim_p_bis        number(*, 5),
    lgr_dim_e_von        number(*, 5),
    lgr_dim_e_bis        number(*, 5),
    lgr_dim_t_von        number(*, 5),
    lgr_dim_t_bis        number(*, 5),
    artikel_id           number(*, 0),
    fa_ag                number(*, 5),
    inv_status           varchar2(10 char) not null enable,
    erstellt_datum       date not null enable,
    erstellt_login_id    number(*, 0),
    soll_start_datum     date,
    ist_start_datum      date,
    ist_start_login_id   number(*, 0),
    ist_ende_datum       date,
    ist_ende_login_id    number(*, 0),
    von_artikel          varchar2(255 char),
    bis_artikel          varchar2(255 char),
    von_datum            date,
    bis_datum            date,
    von_lagerort         number(*, 5),
    bis_lagerort         number(*, 5),
    von_menge            number(*, 3),
    bis_menge            number(*, 3),
    von_transporteinheit varchar2(255 char),
    bis_transporteinheit varchar2(255 char),
    zaehlungsart         varchar2(50 char)
);

alter table dirkspzm32.lvs_inventur_job_kopf
    add constraint pk_lvs_inventur_job_kopf primary key ( inventur_id )
        using index enable;


